property.code:
## Use the current ColorTheme
#template('colorThemeInit.vm')

## Generate reference to background image
#macro(imgURL $name) url($xwiki.getSkinFile("icons/silk/${name}.png")) #end

## Generate reference to background image
#macro(attImgURL $name) url($doc.getAttachmentURL("${name}.png")) #end

/* Settings panel */
.annotationsettings {
  background: $theme.pageContentBackgroundColor; ## $theme.backgroundSecondaryColor;
  border: 1px solid $theme.borderColor;
  border-top: none;
  border-radius: 0 0 10px 10px;
  box-shadow: 0 2px 2px -1px $theme.buttonSecondaryBackgroundColor;
  margin-bottom: -8px;
  padding: 8px 25px; /* Padding left, right = padding of the page content */
  position: relative;
  z-index: 998; /* Right below the submenu. */
}
.floating-menu + .annotationsettings.floating-menu {
  visibility: hidden;
}
.floating-menu:hover + .annotationsettings.floating-menu {
  margin-top: 0;
  visibility: visible;
}
.annotationsettings.floating-menu:hover {
  margin-top: -18px;
  visibility: visible;
}
.annotationsettings.floating-menu:after {
  content: "";
  display: none;
}

.annotationsettings label {
  font-weight: bold;
}
#annotationsdisplay {
  vertical-align: middle;
}

/* Annotations displayed in the text */
.annotation-highlight, .selection-highlight {
  position: relative;
  background-color: var(--mark-bg);
  /* Remove the default mark padding added in bootstrap. 
     The highlights can happen in the middle of words, and it would look odd. */
  padding: 0;
  cursor: pointer;
  &.hovered,
  &.hovered .annotation-highlight, &.hovered .selection-highlight {
    /* We want to increase the accent on the element when hovered. 
       The btn warning background color does that without reducing contrast with the default text color too much. 
       We use this class set dynamically in JS instead of pseudo classes because we want highlights to span multiple
       marks across text blocks. */
    /* We repeat the selector because of nested annotation marks. */
    background-color: var(--mark-highlighted-bg);
  }

  .annotation-toggle {
    /* We don't want the annotation toggle to disturb the text layout. */
    position: absolute;
    margin: 0;
    z-index: 1;
    /* But we still need to center it relative to its parent. */
    top: 50%;
    transform: translateY(-50%);
    transition: opacity .5s ease;
  }

  .annotation-toggle.sr-only {
    opacity: 0;
  }
}

mark.annotation:not(.annotation-highlight) {
  padding: 0;
  background-color: unset;
  color: unset;
}

/* Annotation boxes */
.annotation-bubble {
  background: $theme.backgroundSecondaryColor;
  border: 1px dotted $theme.borderColor;
  width: 560px;
  position: absolute;
  border-radius: 0 10px 10px 10px;
  box-shadow: 0 2px 4px -1px $theme.linkColor;
  margin: 0 10px;
  z-index: 2;
}

.annotation-bubble:before, .annotation-bubble:after {
  content: "";
  display: block;
  position: absolute;
  border-right: 10px solid transparent;
  border-bottom: 10px solid transparent;
}

.annotation-bubble:before {
  top: -1px;
  left: -11px;
  border-right-color: $theme.borderColor;
}
.annotation-bubble:after {
  top: 0;
  left: -10px;
  border-right-color: $theme.backgroundSecondaryColor;
}

.annotation-bubble.annotation-bubble-position-left {
  border-top-left-radius: 10px;
  border-top-right-radius: 0;

  &:before, &:after {
    border-right: none;
    left: unset;
    border-left: 10px solid transparent;
    border-bottom: 10px solid transparent;
  }

  &:before {
    right: -11px;
    border-left-color: $theme.borderColor;
  }

  &:after {
    right: -10px;
    border-left-color: $theme.backgroundSecondaryColor;
  }
}

.annotation-box {
  padding: 6px 12px;
}

.annotation-bubble .loading {
  height: 75px;
}

.annotation-box textarea {
  width: 99%;
}

.annotationAvatar {
  float: left;
  width: 55px;
  text-align: left;
}
.annotationAvatar img {
  max-width: 50px;
  max-height: 50px;
}

#allAnnotations .annotationAvatar  {
  padding-top: 5px;
}

#allAnnotations .annotationHeader, #allAnnotations .annotationContent {
  margin-left: 60px;
}
#allAnnotations .annotationTitle * {
  line-height: 1.4em;
}
.annotation-box .annotationAuthor {
  border-bottom: 1px dotted $theme.borderColor;
  display: block;
}
.annotation-box .sep {
  display: none;
}
.annotation-box .annotationDate {
  padding-top: 3px;
  margin-right: 51px;
  display: block;
}
.annotation-bubble .annotationContent {
  clear: both;
}

.annotation-box .links {
  float: right;
  font-size: 80%;
  text-transform: lowercase;
}

#xwikicontent .annotationAdd {
  background-image: #imgURL('note_add');
}

/* Annotations list (extra-tab) */
#allAnnotations .annotation {
  margin: 0 0 8px;
}
.annotationText {
  padding: 0 36px 0 0;
  text-align: justify;
}
#allAnnotations .UPDATED .annotationText, #xwikicontent .UPDATED {
  ##background-image: #imgURL('note_error');
  background-image: #attImgURL('notesmallorange');
}
#allAnnotations .ALTERED annotationText, #xwikicontent .ALTERED {
  ##background-image: #imgURL('note_delete');
  background-image: #attImgURL('notesmallred');
}

/* General display of an annotation */
.annotationHeader{
  padding: 2px 0px 6px;
}

.annotatedText {
  font-style: italic;
  font-size: 1.2em;
  border-left: none;
  padding: 10px 0;
  margin: 0;
  /* We hide the overflow so that the decorative quote doesn't go over the rest of the UI. */
  overflow: hidden;

  &:before {
    content: "â€œ";
    font-size: 4em;
    line-height: .1em;
    margin-right: .1em;
    vertical-align: -.45em;
    font-family: var(--font-family-serif);
    font-weight: var(--font-weight-semibold);
    font-style: normal;
  }
}

#allAnnotations .annotationHeader:hover {
  background-color: $theme.highlightColor;
}
.annotationDate {
  color: $theme.textSecondaryColor;
  font-size: 80%;
}
.annotationTools {
  display: block;
  float: right;
  margin-top: -1.2em;
}

.annotationTools .reply {
  padding: 1px 3px;
}

.annotationComment {
  padding: 4px 0;
}

dt.annotationLabel label {
  color: $theme.textPrimaryColor;
  font-variant: small-caps;
}

.annotationOriginalSelection {
  color: $theme.textPrimaryColor;
  font-size: 80%;
}

.annotationContent dt {
  margin: 0;
}
.annotationContent dd, .annotationContent blockquote {
  margin-bottom: 10px;
}
.annotationContent blockquote {
  padding-left: 12px;
}
